#!/usr/bin/env python3
import base64, os, subprocess

# Instala o script de backup
b64 = ""
open("/root/backup_diario.sh", "wb").write(base64.b64decode(b64))
os.chmod("/root/backup_diario.sh", 0o755)
print("✓ /root/backup_diario.sh instalado")

# Cria diretório de logs
os.makedirs("/var/log", exist_ok=True)

# Configura cron para rodar todo dia às 03:00
# Primeiro verifica se já existe
result = subprocess.run(["crontab", "-l"], capture_output=True, text=True)
current_cron = result.stdout if result.returncode == 0 else ""

backup_line = "0 3 * * * /root/backup_diario.sh >> /var/log/backup_diario.log 2>&1"

if backup_line in current_cron:
    print("✓ Cron já configurado")
else:
    new_cron = current_cron.rstrip() + "\n" + backup_line + "\n"
    proc = subprocess.run(["crontab", "-"], input=new_cron, text=True)
    print("✓ Cron configurado: todo dia às 03:00")

# Mostra cron atual
result = subprocess.run(["crontab", "-l"], capture_output=True, text=True)
print("\nCron atual:")
print(result.stdout)

# Roda o backup agora para testar
print("\nRodando backup de teste...")
subprocess.run(["/root/backup_diario.sh"])
